+import { $internal } from '../common';
+import { destroyEntity, initializeEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity, releaseEntity } from '../entity/utils/entity-index';
+import { getRelationTargets } from '../relation/relation';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { DeferredWorld, World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+type Buffer = { commands: Command[] };
+type TraitState = Map<Entity, Entity[] | true>;
+type Snapshot = Map<Trait, TraitState>;
+
+function buffer(world: World): Buffer {
+    const buffers = world[$internal].deferredBuffers as Buffer[];
+    let current = buffers[buffers.length - 1];
+    if (!current) current = { commands: [] }, buffers.push(current);
+    return current;
+}
+
+export function createDeferred(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            // Reserve a stable ID now, but do not make it query-visible until playback.
+            const entity = allocateEntity(world[$internal].entityIndex);
+            buffer(world).commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            buffer(world).commands.push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            buffer(world).commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            buffer(world).commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            buffer(world).commands.push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushDeferred(world, buffer(world));
+        },
+    };
+}
+
+export function beginDeferredScope(world: World): Buffer {
+    const scope = { commands: [] };
+    (world[$internal].deferredBuffers as Buffer[]).push(scope);
+    return scope;
+}
+
+export function endDeferredScope(world: World, scope: Buffer): void {
+    const buffers = world[$internal].deferredBuffers as Buffer[];
+    if (buffers[buffers.length - 1] !== scope) return;
+    flushDeferred(world, scope);
+    buffers.pop();
+}
+
+/** Flushes every live scope. Used before an immediate entity mutation/read. */
+export function flushAllDeferred(world: World): void {
+    if (world[$internal].isFlushingDeferred) return;
+    const buffers = world[$internal].deferredBuffers as Buffer[];
+    for (let i = 0; i < buffers.length; i++) flushDeferred(world, buffers[i]);
+}
+
+export function flushDeferred(world: World, target: Buffer): void {
+    const ctx = world[$internal];
+    if (ctx.isFlushingDeferred || target.commands.length === 0) return;
+
+    const commands = target.commands.splice(0);
+    const cancelledSpawns = new Set<Entity>();
+    const spawns = new Set<Entity>();
+    for (const command of commands) {
+        if (command.type === 'spawn') spawns.add(command.entity);
+        else if (command.type === 'destroy' && spawns.has(command.entity)) cancelledSpawns.add(command.entity);
+    }
+
+    const before = snapshot(world);
+    const queryBefore = new Map(ctx.queriesHashMap);
+    const queryEntities = new Map(
+        Array.from(queryBefore.values(), (query) => [query, new Set(query.entities.dense)] as const)
+    );
+
+    ctx.isFlushingDeferred = true;
+    ctx.suppressSubscriptions = true;
+    try {
+        for (const command of commands) {
+            if (cancelledSpawns.has(command.entity)) continue;
+            if (command.type === 'spawn') {
+                initializeEntity(world, command.entity, ...command.traits);
+            } else if (!world.has(command.entity)) {
+                // Entity destruction (including autoDestroy cascades) makes later commands no-ops.
+                continue;
+            } else if (command.type === 'destroy') {
+                destroyEntity(world, command.entity);
+            } else if (command.type === 'add') {
+                applyAdd(world, command.entity, command.traits);
+            } else if (command.type === 'remove') {
+                removeTrait(world, command.entity, ...command.traits);
+            } else {
+                applyExclusive(world, command.entity, command.pair);
+            }
+        }
+    } finally {
+        ctx.suppressSubscriptions = false;
+        ctx.isFlushingDeferred = false;
+        for (const entity of cancelledSpawns) releaseEntity(ctx.entityIndex, entity);
+    }
+
+    notifyTraitSubscriptions(world, before);
+    notifyQuerySubscriptions(world, queryEntities);
+}
+
+function applyAdd(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    for (const config of traits) {
+        addTrait(world, entity, config);
+        if (Array.isArray(config)) {
+            setTrait(world, entity, config[0], config[1], false);
+        } else if (isRelationPair(config) && config[$internal].params !== undefined) {
+            setTrait(world, entity, config, config[$internal].params, false);
+        }
+    }
+}
+
+function applyExclusive(world: World, entity: Entity, pair: RelationPair) {
+    const relation = pair[$internal].relation;
+    // Removing the relation trait clears every existing pair, including for non-exclusive relations.
+    removeTrait(world, entity, relation[$internal].trait);
+    if (pair[$internal].target !== '*') applyAdd(world, entity, [pair]);
+}
+
+function snapshot(world: World): Snapshot {
+    const result: Snapshot = new Map();
+    const ctx = world[$internal];
+    for (const instance of ctx.traitInstances) {
+        if (!instance) continue;
+        const values: TraitState = new Map();
+        const relation = instance.trait[$internal].relation;
+        for (const entity of world.entities) {
+            if (!hasTrait(world, entity, instance.trait)) continue;
+            values.set(entity, relation ? [...getRelationTargets(world, relation, entity)] : true);
+        }
+        result.set(instance.trait, values);
+    }
+    return result;
+}
+
+function notifyTraitSubscriptions(world: World, before: Snapshot) {
+    const after = snapshot(world);
+    const traits = new Set([...before.keys(), ...after.keys()]);
+    for (const trait of traits) {
+        const instance = world[$internal].traitInstances[trait.id];
+        if (!instance) continue;
+        const oldValues = before.get(trait) ?? new Map();
+        const newValues = after.get(trait) ?? new Map();
+        const entities = new Set([...oldValues.keys(), ...newValues.keys()]);
+        const relation = trait[$internal].relation;
+        for (const entity of entities) {
+            if (!relation) {
+                if (!oldValues.has(entity) && newValues.has(entity)) for (const sub of instance.addSubscriptions) sub(entity);
+                if (oldValues.has(entity) && !newValues.has(entity)) for (const sub of instance.removeSubscriptions) sub(entity);
+                continue;
+            }
+            const oldTargets = new Set((oldValues.get(entity) as Entity[] | undefined) ?? []);
+            const newTargets = new Set((newValues.get(entity) as Entity[] | undefined) ?? []);
+            for (const target of oldTargets) if (!newTargets.has(target)) for (const sub of instance.removeSubscriptions) sub(entity, target);
+            for (const target of newTargets) if (!oldTargets.has(target)) for (const sub of instance.addSubscriptions) sub(entity, target);
+        }
+    }
+}
+
+function notifyQuerySubscriptions(world: World, before: Map<any, Set<Entity>>) {
+    for (const [query, oldEntities] of before) {
+        const newEntities = new Set(query.entities.dense);
+        for (const entity of oldEntities) if (!newEntities.has(entity)) for (const sub of query.removeSubscriptions) sub(entity);
+        for (const entity of newEntities) if (!oldEntities.has(entity)) for (const sub of query.addSubscriptions) sub(entity);
+    }
+}
